#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100
#define MAX_M 100
#define MAX_K 100

int X[MAX_N][MAX_M];
int A[MAX_K], B[MAX_K];
int N, M, K;

double calculate_max_average_score() {
    // Build the graph and perform topological sorting
    int graph[MAX_N][MAX_N] = {{0}};
    int in_degree[MAX_N] = {0};
    for (int i = 0; i < K; i++) {
        graph[A[i] - 1][B[i] - 1] = 1;
        in_degree[B[i] - 1]++;
    }

    // Initialize the memoization table
    double memo[MAX_N][MAX_M] = {{0}};
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            memo[i][j] = -1;
        }
    }

    // Calculate the maximum average score for each course and semester
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (X[i][j] != -1) {
                double max_score = X[i][j];
                for (int k = 0; k < N; k++) {
                    if (graph[k][i] == 1) {
                        max_score += memo[k][j - 1];
                    }
                }
                memo[i][j] = max_score;
            }
        }
    }

    // Calculate the maximum average score
    double max_average_score = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (memo[i][j] > max_average_score) {
                max_average_score = memo[i][j];
            }
        }
    }
    return max_average_score / N;
}

int main() {
    scanf("%d %d %d", &N, &M, &K);
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            scanf("%d", &X[i][j]);
        }
    }
    for (int i = 0; i < K; i++) {
        scanf("%d %d", &A[i], &B[i]);
    }
    printf("%.2f\n", calculate_max_average_score());
    return 0;
}

