int A[MAX_K], B[MAX_K];
int N, M, K;

// Function to calculate the maximum average score
double calculate_max_average_score() {
    // Build the graph and perform topological sorting
    vector<vector<int>> graph(N);
    vector<int> in_degree(N, 0);
    for (int i = 0; i < K; i++) {
        graph[A[i] - 1].push_back(B[i] - 1);
        in_degree[B[i] - 1]++;
    }

    // Initialize the memoization table
    vector<vector<double>> memo(N, vector<double>(M, -1));

    // Calculate the maximum average score for each course and semester
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (X[i][j] != -1) {
                double max_score = X[i][j];
                for (int k = 0; k < N; k++) {
                    if (graph[k][i] == 1) {
                        max_score += memo[k][j - 1];
                    }
                }
                memo[i][j] = max_score;
            }
        }
    }

    // Calculate the maximum average score
    double max_average_score = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (memo[i][j] > max_average_score) {
                max_average_score = memo[i][j];
            }
        }
    }
    return max_average_score / N;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    cin >> N >> M >> K;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            cin >> X[i][j];
        }
    }
    for (int i = 0; i < K; i++) {
        cin >> A[i] >> B[i];
    }
    cout << fixed << setprecision(2) << calculate_max_average_score() << endl;
    return 0;
}

